import{_ as t,o as p,c as e,j as r,a,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const l=JSON.parse('{"title":"想要成为假面骑士","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/1.生理类/想要成为假面骑士.md","filePath":"4.资源分区/1.血统与训练/1.生理类/想要成为假面骑士.md"}'),P={name:"4.资源分区/1.血统与训练/1.生理类/想要成为假面骑士.md"};function s(d,b,n,u,X,D){return p(),e("div",null,[...b[0]||(b[0]=[r("h1",{id:"想要成为假面骑士",tabindex:"-1"},[a("想要成为假面骑士 "),r("a",{class:"header-anchor",href:"#想要成为假面骑士","aria-label":'Permalink to "想要成为假面骑士"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌037")])])],-1),o('<h1 id="想要成为假面骑士-1" tabindex="-1">想要成为假面骑士 <a class="header-anchor" href="#想要成为假面骑士-1" aria-label="Permalink to &quot;想要成为假面骑士&quot;">​</a></h1><p>想要成为假面骑士<br> 特异本质<br> 训练<br> 概述：从很小的时候开始，<br> 或者说，那是假面骑士初代，<br> 从那时起，我的心中就被一个身影填满了；<br> 假面骑士。<br> 啊啊，虽然这种想法，对于世界来说，非常的不公平……<br> ……但是，哪怕只有一次也好；<br> 让我见到真正的修卡！！<br> 让我成为——假面骑士！</p><p>特殊的，在购买该训练后，你失去任何购买假面骑士系列相关资源的可能性，<br> 若有可能进入假面骑士世界观，你在影片中也被视为不满足任何变身条件。</p><p>D级：<br> D+600<br> 为了成为假面骑士，训练是必不可少的，训练，无止境的训练，以人类之躯，必须要以绝对的决心与刻苦的训练才能追随那梦想的步伐，一刻也不能停歇。<br> 购买该训练时，若你全身的天生武器伤害不足3L则提升至3L，并且在生理属性相关检定上获得2DP内在加值。从购买该训练开始，你每天(包括在主神空间内)都需要进行一套完整竭力的训练计划，包括但不限于简简单单的1000次俯卧撑1000次引体向1小时马步1000次深蹲10000次击拳10km长跑等；不普通的徒手斩断瀑布，树枝上做倒立俯卧撑，与熊徒手搏斗，在重庆跑酷等等诸如此类。<br> 每日的训练时长不得低于8小时，这代表，你可以零散地安排在每天的剧情中进行训练，也可以直接占据今日长休的时间进行训练(若占据3小时或更多的长休时间将会使你失去长休应得的收益)<br> 若你严格遵守每日至少八小时训练计划，你在影片结束时将获得……满足感，你正在为了成功而前进，不是吗？</p><p>当然，你还是会在影片结束时从中获得仅能用于购买该资源后续及下属的1XP作为奖励，每获得两次这一奖励就额外获得1XP。这些XP在购买该资源后续等级及下属时，可以以1XP=250分，8XP=1D的比例进行直接转换。</p><p>若你连续四场影片坚持严格遵循每日至少八小时训练计划，如此刻苦的努力将使你的意志池上限提升1点，仅获得一次。</p><p>在购买该训练后，你必须要严苛地执行训练，并且惩恶扬善，保护弱者，惩戒恶者，你唯一能够主动攻击并击杀的群体便是假面骑士中的【修卡】或者类似的杂兵群体(如丧尸、血仆、植物怪等)以及【怪人】或类似的个体(如魔物、吸血鬼、邪魔等)，因自卫进行的反击仍然是被允许的。</p><p>C级<br> C+1200<br> 从某个时刻开始，你的训练不再有明显的提升，那些能量仿佛积压在了自己的体内，等待着，等待着某个契机。<br> 从现在开始，你获得决心属性的相关检定上的1DP内在加值，你在维持每日的训练计划之外，也需要通过施展来突破自身的极限，将训练积压的能量激发出来。<br> 每经历一场战胜过同级别战斗的影片后，你将依次获得下列收益，全部获得后不再因此而成长。<br> ●你在力量效果检定上获得1点附加成功，并获得1点快速医疗(12医疗点数)<br> ●你提升1点意志池上限。并获得1点快速医疗(12医疗点数)<br> ●你在生理属性检定上获得传奇决心*1DP内在加值。<br> ●你在力量属性相关的检定上加骰提升一级(至多为8加骰)，意志豁免获得【8加骰】。</p><p>B级<br> B+2400<br> 不断地训练，是否有一刻感觉到了……枯燥?<br> 哪怕到了这个地步，在这样一个【一切资源都能通过兑换获得的】世界里。<br> 如此坚持这种凡俗、枯燥的训练，真的有意义吗？<br> 有。<br> 毫无疑问。<br> 这就是真正的决心，只要多向着梦想接近一分，过去的一切所为就都充满了意义，只要能让自己更优秀一分，自己的未来就更有希望！<br> 不，一直一直，一直都充满着希望！！<br> 所以，开始今天的训练吧。<br> 为了战胜邪恶势力！<br> 为了成为……假面骑士(梦想的自己)！！<br> 现在，完成训练的影片结束后获得的XP收益和额外奖励提高一倍，并且在一场经历过同级别战斗并胜利的影片之后，你在进行生理属性相关检定时获得1dp内在加值成长。<br> 从现在开始，你免疫B级影响心灵来源的负面效果，并获得1点近战伤害吸收，若在承受攻击时，你拥有尚未被完全破除的格挡防御，针对你进行的那次攻击将承受来源于你格挡防御的【劣化2】。<br> 在你进行力量属性相关检定时，你可以获得等同决心属性三分之一的士气加值。</p><p>A级<br> A+4800<br> 长久以来的训练，将在此刻化为实质，一切的努力都是值得的，因为从此刻开始，你意识到，不知不觉间，自己已然跟上了梦想的脚步。<br> 你的影响心灵来源免疫提升为A级，来源于格挡防御的【劣化2】提升为【劣化3】。<br> 拥有该等级后，你获得仅能用于进行攻击或使用该资源下属能力的8AP。</p><p>泪水，或许早就流尽了罢，事到如今，谈何后悔，不妨放眼向前，变强，变强，变得更强，变得比自己曾经憧憬的假面骑士还要更加更加更加的强！我就是，假面骑士！<br> 现在，当你在完成所有日常训练后，于所处的影片中经历过一场至少为同级战斗的胜利后，影片结束时，获得1点决心属性上的附加成功。<br> 在【变身状态】下，相信的心将会赐予你无与伦比的力量，每轮一次，当你在进行攻击时，令那次攻击的出目提升为1.5倍。<br> 汗水会成为独属于你的皮套，你获得【格挡18】，这些防御仅在进行格挡时生效。</p><p>下属技艺：<br> 以下内容皆需要拥有同等级的训练主轴后方能购买，视为技艺（10/20/40/80XP分别对应D/C/B/A级），正常提供自由属性点。</p><p>假面变身<br> 差价升级10XP/20XP/40XP<br> 购买该能力后，你想要成为假面骑士的&quot;心&quot;成为了真正的力量，或许在别人眼里，一个无法变身的人喊着骑士变身是非常中二的行为(事实也的确如此)，但是，这是内心所向往的梦想，而梦想，会因决心而回应你的努力！<br> 你需要选择任意一位假面骑士作为你想要成为的目标，一经选择不可更改，购买该技艺后会赠送你一副对应选择骑士的玩具面具(或者其它可以穿戴在身上的玩具)。<br> 由于无数次模仿假面骑士变身的动作，你可以以一个自由动作几乎在瞬间将面具穿戴在脸上(或将其它玩具穿戴在对应位置)，在这个过程中模仿假面骑士的变身动作并大声喊出：<br> &quot;HEN！！！SHIN！！！！&quot;<br> 如此之后，你视为进入【变身状态】。<br> 在【变身状态】下，心中相信假面骑士的力量将会对应到自己身上，随着相信的等级不断提高，假面变身的力量也将提供更强的能力，同时，你也需要在战斗中进行攻击时大声喊出对应假面骑士的招牌招式名并以招牌动作进行攻击，哪怕那只是一次不附带技艺的普通攻击，你的言行举止也需要与所选骑士一致，以此让自己坚信自身依然处于【变身状态】。<br> D级时，你的伤势不再自然恶化，假面骑士不会因为伤势过重而停下战斗的脚步（ps.并没有获得满严重伤害不昏迷）！你在力量属性相关检定上获得1dp士气加值与1点附加成功。<br> C级时，在D级的基础上，你不再会因被严重伤害填满生命值而昏迷，假面骑士在战斗到最后一刻之前，绝不会倒下！<br> B级时，在C级的基础上，你免疫多次攻击带来的减值，纵使面对围攻，假面骑士依然能坚持战斗，只有杂兵才会围攻，而假面骑士绝不会输给杂兵！当你在承受擒抱时，你可以立即以自身的本能调动身躯进行抵抗，使得那次擒抱无效，这视为你具有免疫擒抱状态的能力，假面骑士可不会陷入这种无趣的战斗啊！<br> 特殊的，当象征着变身状态的物品从身上离开时，直到穿戴上物品前都会失去以上效果。</p><p>骑士拳<br> 差价升级10XP/20XP/40XP/80XP<br> 凝聚力量与决心，在施展时，大声喊出<br> &quot;RI——DA——PUNCH！！！！！&quot;<br> 全力挥出凝聚了无数信念与努力的一拳，凡人的一拳，心中的一拳。<br> 这是一个以标准动作施展的肉搏全力攻击，如字面意义需要使用拳头进行攻击。<br> 这次攻击根据骑士拳的等级D/C/B/A附带有威猛5/10/10/20，这些威猛在计算目标防御后若仍有剩余，则这些剩余威猛等量转化为攻击上的士气加值，并且额外具有2DP/4DP/【决心属性】*1+3DP/不获得加值（对应D/C/B/A级），但在A级时，你可以额外将决心属性加入这次攻击中。</p><p>骑士踢<br> 差价升级20XP/40XP/80XP<br> 赌上一切的舍身一踢，积累而来的力量，拼尽全力的决心，结束战斗的期盼。<br> 将决意于此释放，无论是谁，在踢出这一脚时难免会大声喊出<br> &quot;RIDA——KICK！！！！&quot;<br> 这是一个以整轮动作施展的肉搏冲锋，也视为一次全力攻击，如字面意思般以【腿】作为这次攻击的天生武器进行攻击。</p><p>C级：这次冲锋视为一次跳跃移动，这意味着你需要在移动前如已经进行过助跑般进行一次跳跃检定，将检定出目加入移动距离，并视为跳跃与移动结合，可以准确的控制跳跃的落点和距离而无需检定（跳跃的高度不能超过移动距离的1/2；回合结束时仍然需要站在稳固的落脚点上，否则就会坠落）。这表现为你高高跃起，朝着敌人一脚踢出，这次攻击的冲锋有效距离总是按最大值计算，攻击加骰提升一级(至多8加骰)，并具有【碾压】特性。</p><p>B级：在C级的基础上，这次攻击额外具有【湮灭】特性，并获得4点额外的附加成功。</p><p>A级：在B级的基础上（但失去【碾压】特性与4点附加成功），可以将决心属性加入这次攻击中，你可以在进行这次攻击时额外消耗1点意志力，令被命中的目标需要使用强韧豁免对抗伤害出目，否则视为陷入A级创伤来源的【震慑】效果，持续一轮。</p><p>抗击打训练<br> 差价升级10XP/20XP/40XP<br> 为了在实战中保持足够的战斗力，抗击打训练绝对是必要的，不仅是自身的身躯硬抗攻击，还有对攻击进行招架的训练，避免自身快速失去战斗力是这个训练的重点。<br> 在购买该技艺的D级后，每天需要用半个小时的时间进行抗击打训练，在保证每日训练的情况下，每场影片结束后，你将获得1点天生防御与1点仅在格挡时生效的格挡防御。<br> 那之后每次升级都会得到不同的提升。<br> C级：在D级的基础上，通过抗击打与抵抗伤害的架势对近身战进行有效防守，你获得免疫接触攻击的能力。<br> B级：通过不断地磨炼肉体韧性，不断地打磨肉体本身的防御能力，有朝一日，你的身体就连怪人的利爪都能抵挡。在C级的基础上，你获得基于格挡防御的【超级坚韧】特性。</p><p>假面武毅<br> 差价升级10XP/20XP/40XP/80XP<br> 为了模仿假面骑士而不断精进自身，从梦想中磨炼而出的战斗方式，这是&quot;假面骑士的战斗方式&quot;，所以在攻击时，结合正在施展的战斗技艺，可以依靠该能力强行转变为骑士特摄剧集的出招风格，例如可以将普通的肘击通过大喊&quot;骑士肘！！&quot;来赋予该技艺的效果，其余攻击也同理；这也是凡人的决心与毅力，是&quot;向往英雄的普通人的战斗方式&quot;，所以在战斗中，拥有各式各样减少自身受到伤害的方式，例如拼尽全力用手肘和膝盖抵住攻击等等。<br> 是攻防一体的技艺。<br> 在进行攻击范围为触及、攻击方式为肉搏或对应选择假面骑士风格的武器时，可以根据该技艺的等级D/C/B/A应用下列效果。<br> D级：你的攻击额外获得1点附加成功，你可以在攻击时扣除自身传奇决心*3点攻击dp，以此换取自身传奇决心点*1点附加成功。承受攻击时，你获得基于格挡防御的【防能量】。<br> C级：在D级的基础上，每场景一次，你可以以一个自由动作将一种在装备的肉搏武器拥有的所有武器伤害转化为在格挡时生效的格挡防御，持续一场景，若自身未装备武器，则改为转变天生武器伤害为格挡时生效的格挡防御。<br> B级：购买时选择，在C级的基础上，获得【看破】特性，或获得2点格挡防御与2dp力量属性相关检定上的士气加值，并在这两者上获得1点附加成功。<br> A级：在B级的基础上，每轮一次，你在进行攻击时可以重新投掷一次取优结算。每轮一次，你在遭受攻击时可以令对方这次攻击重新投掷一次取劣结算。</p><p>超级感官<br> 差价升级10XP/20XP/40XP<br> 假面骑士初代、V2、V3乃至骑士人……他们通过人体改造和各类科技总能使得自身的感官上升到一种非凡的强度，而感觉是可以锻炼的，落水辩位，逆风闻香，目视远山，只要能锻炼，就能不断精进，为了成为假面骑士，这点锻炼算得了什么？<br> 购买该技艺后你每天需要额外用半个小时的时间训练自身的五感，在保证每日训练的情况下，根据技艺等级D/C/B你获得该技艺的增益效果：<br> D级：你的视觉感知提升为线性强感知方式，可以精准地看到敏感范围内树皮上的每一道沟壑，眼前飞过的苍蝇腿上的刚毛沾染的食物残渣，你对于视力的保护训练使你免疫目眩异常点数的影响与严重负面效果。<br> C级：在D级的基础上，你的嗅觉感知方式提升为非线性强感知方式，你在逆风状态下依然能精准分辨敏感范围内传来的每个味道代表的具体方位，并且通过气味位置的变化倒推气流的流动以及生物的移动，你也能在听到声音后立即锁定具体方位，对敏感范围内的生物进行精准定位，同时，你对于听力的保护训练使你免疫耳鸣异常点数的影响与严重负面效果。<br> B级：在C级的基础上，你将自身的视听嗅三觉磨炼到一种极致，这是一种特殊的状态，仿佛世界在告诉你信息，而不是你在去分辨信息，现在，你可以立即感受到敏感范围内是否存在对你抱有敌意的单位，如果你额外支付6XP，则你还可以随时沉下心去感受世间，从而得知影片内是否出现过【修卡】，这一目标也可以替换为任何的【黑恶势力】或者任意一个名词，你会得知这个名词指代的目标所在的具体位置(某个建筑、某个集团、势力等)，时间上的误差不会超过一周，这是一个B级别、变形来源的预知效果。<br> 用进废退，若你连续两天没有完成五感训练，你将会失去这一技艺的效益。</p><p>假面防御<br> 差价升级10XP/20XP/40XP<br> 在TV上无数次看到过，那些总是战败的假面骑士最终的问题都能归咎于他们无法平衡自身的攻击与防御，想要成为假面骑士，成为完美的假面骑士，就需要亲自去补足这一切！<br> 在购买该技艺后，你通过无尽的训练将防御刻入了本能，根据技艺等级D/C/B将获得增益效果，高等级替换低等级效果。<br> D级：你获得来源于肉体的【格挡5】。<br> C级：你获得来源于肉体的【格挡5】与2点格挡防御上的附加成功。<br> B级：你获得来源于肉体的【格挡5】。并且你可以随时格挡来袭的攻击，这意味着无论何时，无论是否处于战斗中，无论是否在你的回合内，你总是视为已经进行了格挡。</p><p>&quot;心&quot;<br> B+2000或40XP<br> 从什么时候开始呢……<br> 好像从哪一天起床之后，<br> 就忘记了过去的自己。<br> 因为那是&quot;幼稚&quot;的自己，那是不堪回首的曾经，那是回忆起来会摇头叹息的过往，<br> 就连过去的自己最爱的事物都一并被抛弃了。<br> ……<br> 这样的，<br> &quot;平凡&quot;……不，&quot;平庸&quot;的人生——<br> 我不接受。<br> 我要成为……<br> 假！面！骑！士！<br> 你在B级训练等级中获得的&quot;在你进行力量属性相关检定时，你可以将该训练B级中决心属性三分之一的加值提升至等同决心属性等额的士气加值。</p><p>从购买该技艺开始，只要你的心中依然在坚持自己的梦想，只要你依然还在惩奸除恶，只要你依然还在提升自我，只要你经历了无悔的一场影片，你就会获得1层【心】。<br> 【心】：每拥有一层该特性，你就在力量和决心相关检定上获得1DP内在加值。<br> 每获得3层【心】就在力量和决心属性相关检定上额外获得1点附加成功。每以此获得3点附加成功就会再获得1点附加成功。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',26)])])}const q=t(P,[["render",s]]);export{l as __pageData,q as default};
